parameters.jsCode:
const candidates = $json.candidates || [];
const text = candidates?.[0]?.content?.parts?.[0]?.text || '';

let reply = {};
try {
  const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    reply = JSON.parse(jsonMatch[1]);
  } else {
    reply = JSON.parse(text);
  }
} catch (e) {
  reply = {
    reply: text.slice(0, 200),
    tone_used: 'friendly',
    sentiment_detected: 'neutral',
    cta_included: false
  };
}

const prevData = $('Parse Comment Data').first().json;
return [{
  json: {
    platform: prevData.platform,
    comment_id: prevData.comment_id,
    commenter_name: prevData.commenter_name,
    comment_text: prevData.comment_text,
    reply: reply.reply || '',
    tone_used: reply.tone_used || 'friendly',
    sentiment_detected: reply.sentiment_detected || 'neutral',
    cta_included: reply.cta_included || false,
    created_at: new Date().toISOString()
  }
}];
